package org.eclipse.rdf4j.sail.lmdb;

import static org.junit.jupiter.api.Assertions.assertEquals;

import java.io.File;
import java.util.LinkedHashSet;
import java.util.Set;

import org.eclipse.rdf4j.model.IRI;
import org.eclipse.rdf4j.model.Literal;
import org.eclipse.rdf4j.model.Value;
import org.eclipse.rdf4j.model.util.Values;
import org.eclipse.rdf4j.model.vocabulary.XSD;
import org.eclipse.rdf4j.query.TupleQueryResult;
import org.eclipse.rdf4j.repository.sail.SailRepository;
import org.junit.jupiter.api.AfterEach;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.io.TempDir;

class LmdbValueAwareNumericFilterTest {

	private static final String NS = "urn:lmdb-value-aware:";
	private static final IRI P = Values.iri(NS, "p");

	private SailRepository repository;

	@BeforeEach
	void setUp(@TempDir File dataDir) {
		LmdbStore store = new LmdbStore(dataDir);
		repository = new SailRepository(store);
		repository.init();
	}

	@AfterEach
	void tearDown() {
		repository.shutDown();
	}

	@Test
	void exactTriplePatternStillMatchesOnlyTheStoredLiteralTerm() {
		loadNumericVariants();

		Set<String> subjects = subjects("""
				SELECT ?s WHERE {
					?s <urn:lmdb-value-aware:p> "1"^^<http://www.w3.org/2001/XMLSchema#integer> .
				}
				""");

		assertEquals(Set.of("urn:lmdb-value-aware:c"), subjects);
	}

	@Test
	void numericEqualityFilterReturnsOriginalStoredLiteralVariants() {
		loadNumericVariants();

		Set<String> values = values("""
				SELECT ?v WHERE {
					?s <urn:lmdb-value-aware:p> ?v .
					FILTER (?v = "1"^^<http://www.w3.org/2001/XMLSchema#integer>)
				}
				""");

		assertEquals(Set.of("\"001\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"1\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"1.0\"^^<http://www.w3.org/2001/XMLSchema#decimal>"), values);
	}

	@Test
	void numericInFilterDeduplicatesValuesButReturnsOriginalStoredLiteralVariants() {
		loadNumericVariants();

		Set<String> values = values("""
				SELECT ?v WHERE {
					?s <urn:lmdb-value-aware:p> ?v .
					FILTER (?v IN (
						"1"^^<http://www.w3.org/2001/XMLSchema#integer>,
						"1.0"^^<http://www.w3.org/2001/XMLSchema#decimal>,
						"2"^^<http://www.w3.org/2001/XMLSchema#integer>
					))
				}
				""");

		assertEquals(Set.of("\"001\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"1\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"1.0\"^^<http://www.w3.org/2001/XMLSchema#decimal>",
				"\"2\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"2.0\"^^<http://www.w3.org/2001/XMLSchema#decimal>"), values);
	}

	@Test
	void numericNotEqualsFilterRejectsEveryVariantOfTheComparedValue() {
		loadNumericVariants();

		Set<String> values = values("""
				SELECT ?v WHERE {
					?s <urn:lmdb-value-aware:p> ?v .
					FILTER (?v != "1"^^<http://www.w3.org/2001/XMLSchema#integer>)
				}
				""");

		assertEquals(Set.of("\"2\"^^<http://www.w3.org/2001/XMLSchema#integer>",
				"\"2.0\"^^<http://www.w3.org/2001/XMLSchema#decimal>"), values);
	}

	private void loadNumericVariants() {
		try (var connection = repository.getConnection()) {
			connection.add(Values.iri(NS, "a"), P, literal("001", XSD.INTEGER));
			connection.add(Values.iri(NS, "b"), P, literal("1.0", XSD.DECIMAL));
			connection.add(Values.iri(NS, "c"), P, literal("1", XSD.INTEGER));
			connection.add(Values.iri(NS, "d"), P, literal("2", XSD.INTEGER));
			connection.add(Values.iri(NS, "e"), P, literal("2.0", XSD.DECIMAL));
		}
	}

	private static Literal literal(String label, IRI datatype) {
		return Values.literal(label, datatype);
	}

	private Set<String> subjects(String query) {
		return bindingValues(query, "s");
	}

	private Set<String> values(String query) {
		return bindingValues(query, "v");
	}

	private Set<String> bindingValues(String query, String bindingName) {
		try (var connection = repository.getConnection();
				TupleQueryResult result = connection.prepareTupleQuery(query).evaluate()) {
			Set<String> values = new LinkedHashSet<>();
			while (result.hasNext()) {
				Value value = result.next().getValue(bindingName);
				values.add(value.toString());
			}
			return values;
		}
	}
}
